/**
 * Get word-by-word translation for a text
 */
export function getWordByWord(textId: string): WordTranslation[] | undefined {
  return wordByWordTranslations[textId];
}

/**
 * Check if a text has word-by-word translation
 */
export function hasWordByWord(textId: string): boolean {
  return textId in wordByWordTranslations;
}

/**
 * Get coverage statistics
 */
export function getWordByWordCoverage(): { level: string; count: number; total: number }[] {
  const ids = Object.keys(wordByWordTranslations);
  return [
    { level: 'beginner', count: ids.filter(id => id.startsWith('b')).length, total: 90 },
    { level: 'intermediate', count: ids.filter(id => id.startsWith('i')).length, total: 76 },
    { level: 'advanced', count: ids.filter(id => id.startsWith('a')).length, total: 61 },
  ];
}
